def to_notebook_table(df):
    columns = []
    for column_name in df.columns:
        series = df[column_name]
        if pd.api.types.is_bool_dtype(series):
            column_type = "boolean"
        elif pd.api.types.is_integer_dtype(series):
            column_type = "integer"
        elif pd.api.types.is_numeric_dtype(series):
            column_type = "number"
        elif pd.api.types.is_datetime64_any_dtype(series):
            column_type = "datetime"
        else:
            column_type = "string"
        columns.append({"name": str(column_name), "type": column_type})

    values_df = df.copy()
    for column_name in values_df.columns:
        if pd.api.types.is_datetime64_any_dtype(values_df[column_name]):
            values_df[column_name] = values_df[column_name].dt.strftime("%Y-%m-%dT%H:%M:%SZ")

    return {
        "columns": columns,
        "values": values_df.astype(object).where(pd.notnull(values_df), None).values.tolist()
    }

